import java.util.*;class P7{static boolean p1(String s){int l=0,r=s.length()-1;while(l<r){if(s.charAt(l)!=s.charAt(r))return false;l++;r--;}return true;}static boolean p2(String s,int l,int r){if(l>=r)return true;if(s.charAt(l)!=s.charAt(r))return false;return p2(s,l+1,r-1);}static boolean p3(String s){char[] a=s.toCharArray();int n=a.length;for(int i=0;i<n/2;i++)if(a[i]!=a[n-1-i])return false;return true;}public static void main(String[] a){Scanner s=new Scanner(System.in);String t=s.next();System.out.println(p1(t));System.out.println(p2(t,0,t.length()-1));System.out.println(p3(t));}}